  1 | //! A2A Server - serve as an A2A agent
  2 | 
  3 | use super::types::*;
  4 | use crate::session::{Session, SessionEvent};
  5 | use crate::telemetry::record_persistent;
  6 | use anyhow::Result;
  7 | use axum::{
  8 |     Router,
  9 |     extract::State,
 10 |     http::StatusCode,
 11 |     response::Json,
 12 |     routing::{get, post},
 13 | };
 14 | use dashmap::DashMap;
 15 | use std::sync::Arc;
 16 | use std::time::{Duration, Instant};
 17 | use tokio::sync::mpsc;
 18 | use uuid::Uuid;
 19 | 
 20 | /// A2A Server state
 21 | #[derive(Clone)]
 22 | pub struct A2AServer {
 23 |     tasks: Arc<DashMap<String, Task>>,
 24 |     agent_card: AgentCard,
 25 |     /// Optional bus for emitting session events for SSE streaming
 26 |     bus: Option<Arc<crate::bus::AgentBus>>,
 27 | }
 28 | 
 29 | impl A2AServer {
 30 |     /// Create a new A2A server without a bus
 31 |     pub fn new(agent_card: AgentCard) -> Self {
 32 |         Self {
 33 |             tasks: Arc::new(DashMap::new()),
 34 |             agent_card,
 35 |             bus: None,
 36 |         }
 37 |     }
 38 | 
 39 |     /// Create a new A2A server with a bus for event streaming
 40 |     pub fn with_bus(agent_card: AgentCard, bus: Arc<crate::bus::AgentBus>) -> Self {
 41 |         Self {
 42 |             tasks: Arc::new(DashMap::new()),
 43 |             agent_card,
 44 |             bus: Some(bus),
 45 |         }
 46 |     }
 47 | 
 48 |     /// Create the router for A2A endpoints
 49 |     pub fn router(self) -> Router {
 50 |         Router::new()
 51 |             .route("/.well-known/agent.json", get(get_agent_card))
 52 |             .route("/.well-known/agent-card.json", get(get_agent_card))
 53 |             .route("/", post(handle_rpc))
 54 |             .with_state(self)
 55 |     }
 56 | 
 57 |     /// Get the agent card for this server
 58 |     #[allow(dead_code)]
 59 |     pub fn card(&self) -> &AgentCard {
 60 |         &self.agent_card
 61 |     }
