138 | fn record_a2a_message_telemetry(
139 |     tool_name: &str,
140 |     task_id: &str,
141 |     blocking: bool,
142 |     prompt: &str,
143 |     duration: Duration,
144 |     success: bool,
145 |     output: Option<String>,
146 |     error: Option<String>,
147 | ) {
148 |     let record = crate::telemetry::A2AMessageRecord {
149 |         tool_name: tool_name.to_string(),
150 |         task_id: task_id.to_string(),
151 |         blocking,
152 |         prompt: prompt.to_string(),
153 |         duration_ms: duration.as_millis() as u64,
154 |         success,
155 |         output,
156 |         error,
157 |         timestamp: chrono::Utc::now(),
158 |     };
159 |     let _ = record_persistent(
160 |         "a2a_message",
161 |         &serde_json::to_value(&record).unwrap_or_default(),
162 |     );
163 | }
