165 | /// Handle JSON-RPC requests
166 | async fn handle_rpc(
167 |     State(server): State<A2AServer>,
168 |     Json(request): Json<JsonRpcRequest>,
169 | ) -> Result<Json<JsonRpcResponse>, (StatusCode, Json<JsonRpcResponse>)> {
170 |     let request_id = request.id.clone();
171 |     let response = match request.method.as_str() {
172 |         "message/send" => handle_message_send(&server, request).await,
173 |         "message/stream" => handle_message_stream(&server, request).await,
174 |         "tasks/get" => handle_tasks_get(&server, request).await,
175 |         "tasks/cancel" => handle_tasks_cancel(&server, request).await,
176 |         _ => Err(JsonRpcError::method_not_found(&request.method)),
177 |     };
178 | 
179 |     match response {
180 |         Ok(result) => Ok(Json(JsonRpcResponse {
181 |             jsonrpc: "2.0".to_string(),
182 |             id: request_id.clone(),
183 |             result: Some(result),
184 |             error: None,
185 |         })),
186 |         Err(error) => Err((
187 |             StatusCode::OK,
188 |             Json(JsonRpcResponse {
189 |                 jsonrpc: "2.0".to_string(),
190 |                 id: request_id,
191 |                 result: None,
192 |                 error: Some(error),
193 |             }),
194 |         )),
195 |     }
196 | }
197 | 
198 | async fn handle_message_send(
199 |     server: &A2AServer,
200 |     request: JsonRpcRequest,
201 | ) -> Result<serde_json::Value, JsonRpcError> {
202 |     let params: MessageSendParams = serde_json::from_value(request.params)
203 |         .map_err(|e| JsonRpcError::invalid_params(format!("Invalid parameters: {}", e)))?;
204 | 
205 |     // Create a new task
206 |     let task_id = params
207 |         .message
208 |         .task_id
209 |         .clone()
210 |         .unwrap_or_else(|| Uuid::new_v4().to_string());
211 | 
212 |     let task = Task {
213 |         id: task_id.clone(),
214 |         context_id: params.message.context_id.clone(),
215 |         status: TaskStatus {
216 |             state: TaskState::Working,
217 |             message: Some(params.message.clone()),
218 |             timestamp: Some(chrono::Utc::now().to_rfc3339()),
219 |         },
220 |         artifacts: vec![],
221 |         history: vec![params.message.clone()],
222 |         metadata: std::collections::HashMap::new(),
223 |     };
224 | 
225 |     server.tasks.insert(task_id.clone(), task.clone());
226 | 
227 |     // Extract prompt text from message parts
228 |     let prompt: String = params
229 |         .message
230 |         .parts
231 |         .iter()
232 |         .filter_map(|p| match p {
233 |             Part::Text { text } => Some(text.as_str()),
234 |             _ => None,
235 |         })
236 |         .collect::<Vec<_>>()
237 |         .join("\n");
238 | 
239 |     if prompt.is_empty() {
240 |         // Update task to failed
241 |         if let Some(mut t) = server.tasks.get_mut(&task_id) {
242 |             t.status.state = TaskState::Failed;
243 |             t.status.timestamp = Some(chrono::Utc::now().to_rfc3339());
244 |         }
245 |         return Err(JsonRpcError::invalid_params("No text content in message"));
246 |     }
247 | 
248 |     // Determine if blocking (default true for message/send)
249 |     let blocking = params
250 |         .configuration
251 |         .as_ref()
252 |         .and_then(|c| c.blocking)
253 |         .unwrap_or(true);
254 | 
255 |     if blocking {
256 |         // Synchronous execution: create session, run prompt, return completed task
257 |         let mut session = Session::new().await.map_err(|e| {
258 |             JsonRpcError::internal_error(format!("Failed to create session: {}", e))
259 |         })?;
260 |         let started_at = Instant::now();
261 | 
262 |         match session.prompt(&prompt).await {
263 |             Ok(result) => {
264 |                 let result_text = result.text;
265 |                 let response_message = Message {
266 |                     message_id: Uuid::new_v4().to_string(),
267 |                     role: MessageRole::Agent,
268 |                     parts: vec![Part::Text {
269 |                         text: result_text.clone(),
270 |                     }],
271 |                     context_id: params.message.context_id.clone(),
272 |                     task_id: Some(task_id.clone()),
273 |                     metadata: std::collections::HashMap::new(),
274 |                     extensions: vec![],
275 |                 };
276 | 
277 |                 let artifact = Artifact {
278 |                     artifact_id: Uuid::new_v4().to_string(),
279 |                     parts: vec![Part::Text {
280 |                         text: result_text.clone(),
281 |                     }],
282 |                     name: Some("response".to_string()),
283 |                     description: None,
284 |                     metadata: std::collections::HashMap::new(),
285 |                     extensions: vec![],
286 |                 };
287 | 
288 |                 if let Some(mut t) = server.tasks.get_mut(&task_id) {
289 |                     t.status.state = TaskState::Completed;
290 |                     t.status.message = Some(response_message.clone());
291 |                     t.status.timestamp = Some(chrono::Utc::now().to_rfc3339());
292 |                     t.artifacts.push(artifact.clone());
293 |                     t.history.push(response_message);
294 | 
295 |                     let status_event = TaskStatusUpdateEvent {
296 |                         id: task_id.clone(),
297 |                         status: t.status.clone(),
298 |                         is_final: true,
299 |                         metadata: std::collections::HashMap::new(),
300 |                     };
301 |                     let artifact_event = TaskArtifactUpdateEvent {
302 |                         id: task_id.clone(),
303 |                         artifact,
304 |                         metadata: std::collections::HashMap::new(),
305 |                     };
306 |                     tracing::debug!(
307 |                         task_id = %task_id,
308 |                         event = ?StreamEvent::StatusUpdate(status_event),
309 |                         "Task completed"
310 |                     );
311 |                     tracing::debug!(
312 |                         task_id = %task_id,
313 |                         event = ?StreamEvent::ArtifactUpdate(artifact_event),
314 |                         "Artifact produced"
315 |                     );
316 |                 }
317 | 
318 |                 record_a2a_message_telemetry(
319 |                     "a2a_message_send",
320 |                     &task_id,
321 |                     true,
322 |                     &prompt,
323 |                     started_at.elapsed(),
324 |                     true,
325 |                     Some(result_text),
326 |                     None,
327 |                 );
328 |             }
329 |             Err(e) => {
330 |                 let error_message = Message {
331 |                     message_id: Uuid::new_v4().to_string(),
332 |                     role: MessageRole::Agent,
333 |                     parts: vec![Part::Text {
334 |                         text: format!("Error: {}", e),
335 |                     }],
336 |                     context_id: params.message.context_id.clone(),
337 |                     task_id: Some(task_id.clone()),
338 |                     metadata: std::collections::HashMap::new(),
339 |                     extensions: vec![],
340 |                 };
341 | 
342 |                 if let Some(mut t) = server.tasks.get_mut(&task_id) {
343 |                     t.status.state = TaskState::Failed;
344 |                     t.status.message = Some(error_message);
345 |                     t.status.timestamp = Some(chrono::Utc::now().to_rfc3339());
346 |                 }
347 | 
348 |                 record_a2a_message_telemetry(
349 |                     "a2a_message_send",
350 |                     &task_id,
351 |                     true,
352 |                     &prompt,
353 |                     started_at.elapsed(),
354 |                     false,
355 |                     None,
356 |                     Some(e.to_string()),
357 |                 );
358 |             }
359 |         }
360 |     } else {
361 |         // Async execution: spawn background task, return immediately with Working state
362 |         let tasks = server.tasks.clone();
363 |         let context_id = params.message.context_id.clone();
364 |         let spawn_task_id = task_id.clone();
365 | 
366 |         tokio::spawn(async move {
367 |             let task_id = spawn_task_id;
368 |             let started_at = Instant::now();
369 |             let mut session = match Session::new().await {
370 |                 Ok(s) => s,
371 |                 Err(e) => {
372 |                     tracing::error!("Failed to create session for task {}: {}", task_id, e);
373 |                     if let Some(mut t) = tasks.get_mut(&task_id) {
374 |                         t.status.state = TaskState::Failed;
375 |                         t.status.timestamp = Some(chrono::Utc::now().to_rfc3339());
376 |                     }
377 |                     record_a2a_message_telemetry(
378 |                         "a2a_message_send",
379 |                         &task_id,
380 |                         false,
381 |                         &prompt,
382 |                         started_at.elapsed(),
383 |                         false,
384 |                         None,
385 |                         Some(e.to_string()),
386 |                     );
387 |                     return;
388 |                 }
389 |             };
390 | 
391 |             match session.prompt(&prompt).await {
392 |                 Ok(result) => {
393 |                     let result_text = result.text;
394 |                     let response_message = Message {
395 |                         message_id: Uuid::new_v4().to_string(),
396 |                         role: MessageRole::Agent,
397 |                         parts: vec![Part::Text {
398 |                             text: result_text.clone(),
399 |                         }],
400 |                         context_id,
401 |                         task_id: Some(task_id.clone()),
402 |                         metadata: std::collections::HashMap::new(),
403 |                         extensions: vec![],
404 |                     };
405 | 
406 |                     let artifact = Artifact {
407 |                         artifact_id: Uuid::new_v4().to_string(),
408 |                         parts: vec![Part::Text {
409 |                             text: result_text.clone(),
410 |                         }],
411 |                         name: Some("response".to_string()),
412 |                         description: None,
413 |                         metadata: std::collections::HashMap::new(),
414 |                         extensions: vec![],
415 |                     };
416 | 
417 |                     if let Some(mut t) = tasks.get_mut(&task_id) {
418 |                         t.status.state = TaskState::Completed;
419 |                         t.status.message = Some(response_message.clone());
420 |                         t.status.timestamp = Some(chrono::Utc::now().to_rfc3339());
421 |                         t.artifacts.push(artifact);
422 |                         t.history.push(response_message);
423 |                     }
424 | 
425 |                     record_a2a_message_telemetry(
426 |                         "a2a_message_send",
427 |                         &task_id,
428 |                         false,
429 |                         &prompt,
430 |                         started_at.elapsed(),
431 |                         true,
432 |                         Some(result_text),
433 |                         None,
434 |                     );
435 |                 }
436 |                 Err(e) => {
437 |                     tracing::error!("Task {} failed: {}", task_id, e);
438 |                     if let Some(mut t) = tasks.get_mut(&task_id) {
439 |                         t.status.state = TaskState::Failed;
440 |                         t.status.timestamp = Some(chrono::Utc::now().to_rfc3339());
441 |                     }
442 |                     record_a2a_message_telemetry(
443 |                         "a2a_message_send",
444 |                         &task_id,
445 |                         false,
446 |                         &prompt,
447 |                         started_at.elapsed(),
448 |                         false,
449 |                         None,
450 |                         Some(e.to_string()),
451 |                     );
452 |                 }
453 |             }
454 |         });
455 |     }
456 | 
457 |     // Return current task state wrapped in SendMessageResponse
458 |     let task = server.tasks.get(&task_id).unwrap();
459 |     let response = SendMessageResponse::Task(task.value().clone());
460 |     serde_json::to_value(response)
461 |         .map_err(|e| JsonRpcError::internal_error(format!("Serialization error: {}", e)))
462 | }
