464 | async fn handle_message_stream(
465 |     server: &A2AServer,
466 |     request: JsonRpcRequest,
467 | ) -> Result<serde_json::Value, JsonRpcError> {
468 |     // message/stream submits the task for async processing.
469 |     // The client should poll tasks/get for status updates.
470 |     // True SSE streaming requires a dedicated endpoint outside JSON-RPC.
471 | 
472 |     let params: MessageSendParams = serde_json::from_value(request.params)
473 |         .map_err(|e| JsonRpcError::invalid_params(format!("Invalid parameters: {}", e)))?;
474 | 
475 |     let task_id = params
476 |         .message
477 |         .task_id
478 |         .clone()
479 |         .unwrap_or_else(|| Uuid::new_v4().to_string());
480 | 
481 |     let task = Task {
482 |         id: task_id.clone(),
483 |         context_id: params.message.context_id.clone(),
484 |         status: TaskStatus {
485 |             state: TaskState::Working,
486 |             message: Some(params.message.clone()),
487 |             timestamp: Some(chrono::Utc::now().to_rfc3339()),
488 |         },
489 |         artifacts: vec![],
490 |         history: vec![params.message.clone()],
491 |         metadata: std::collections::HashMap::new(),
492 |     };
493 | 
494 |     server.tasks.insert(task_id.clone(), task.clone());
495 | 
496 |     // Extract prompt
497 |     let prompt: String = params
498 |         .message
499 |         .parts
500 |         .iter()
501 |         .filter_map(|p| match p {
502 |             Part::Text { text } => Some(text.as_str()),
503 |             _ => None,
504 |         })
505 |         .collect::<Vec<_>>()
506 |         .join("\n");
507 | 
508 |     if prompt.is_empty() {
509 |         if let Some(mut t) = server.tasks.get_mut(&task_id) {
510 |             t.status.state = TaskState::Failed;
511 |             t.status.timestamp = Some(chrono::Utc::now().to_rfc3339());
512 |         }
513 |         return Err(JsonRpcError::invalid_params("No text content in message"));
514 |     }
515 | 
516 |     // Spawn async processing with event streaming
517 |     let tasks = server.tasks.clone();
518 |     let context_id = params.message.context_id.clone();
519 |     let spawn_task_id = task_id.clone();
520 |     let bus = server.bus.clone();
521 | 
522 |     tokio::spawn(async move {
523 |         let task_id = spawn_task_id;
524 |         let started_at = Instant::now();
525 | 
526 |         // Create a channel for session events
527 |         let (event_tx, mut event_rx) = mpsc::channel::<SessionEvent>(256);
528 | 
529 |         let mut session = match Session::new().await {
530 |             Ok(s) => s,
531 |             Err(e) => {
532 |                 tracing::error!(
533 |                     "Failed to create session for stream task {}: {}",
534 |                     task_id,
535 |                     e
536 |                 );
537 |                 if let Some(mut t) = tasks.get_mut(&task_id) {
538 |                     t.status.state = TaskState::Failed;
539 |                     t.status.timestamp = Some(chrono::Utc::now().to_rfc3339());
540 |                 }
541 |                 record_a2a_message_telemetry(
542 |                     "a2a_message_stream",
543 |                     &task_id,
544 |                     false,
545 |                     &prompt,
546 |                     started_at.elapsed(),
547 |                     false,
548 |                     None,
549 |                     Some(e.to_string()),
550 |                 );
551 |                 return;
552 |             }
553 |         };
554 | 
555 |         // Spawn a task to forward session events to the bus
556 |         let bus_clone = bus.clone();
557 |         let task_id_clone = task_id.clone();
558 |         tokio::spawn(async move {
559 |             while let Some(event) = event_rx.recv().await {
560 |                 let event_data = match &event {
561 |                     SessionEvent::Thinking => {
562 |                         serde_json::json!({ "type": "thinking" })
563 |                     }
564 |                     SessionEvent::ToolCallStart { name, arguments } => {
565 |                         serde_json::json!({
566 |                             "type": "tool_call_start",
567 |                             "name": name,
568 |                             "arguments": arguments
569 |                         })
570 |                     }
571 |                     SessionEvent::ToolCallComplete {
572 |                         name,
573 |                         output,
574 |                         success,
575 |                     } => {
576 |                         serde_json::json!({
577 |                             "type": "tool_call_complete",
578 |                             "name": name,
579 |                             "output": output.chars().take(500).collect::<String>(),
580 |                             "success": success
581 |                         })
582 |                     }
583 |                     SessionEvent::TextChunk(text) => {
584 |                         serde_json::json!({ "type": "text_chunk", "text": text })
585 |                     }
586 |                     SessionEvent::TextComplete(text) => {
587 |                         serde_json::json!({ "type": "text_complete", "text": text })
588 |                     }
589 |                     SessionEvent::ThinkingComplete(thought) => {
590 |                         serde_json::json!({ "type": "thinking_complete", "thought": thought })
591 |                     }
592 |                     SessionEvent::UsageReport {
593 |                         prompt_tokens,
594 |                         completion_tokens,
595 |                         duration_ms,
596 |                         model,
597 |                     } => {
598 |                         serde_json::json!({
599 |                             "type": "usage_report",
600 |                             "prompt_tokens": prompt_tokens,
601 |                             "completion_tokens": completion_tokens,
602 |                             "duration_ms": duration_ms,
603 |                             "model": model
604 |                         })
605 |                     }
606 |                     SessionEvent::Done => {
607 |                         serde_json::json!({ "type": "done" })
608 |                     }
609 |                     SessionEvent::Error(err) => {
610 |                         serde_json::json!({ "type": "error", "error": err })
611 |                     }
612 |                     SessionEvent::SessionSync(_) => {
613 |                         continue; // Don't emit session sync to SSE
614 |                     }
615 |                 };
616 | 
617 |                 // Emit to bus for SSE subscribers
618 |                 if let Some(ref bus) = bus_clone {
619 |                     let handle = bus.handle("a2a-stream");
620 |                     handle.send(
621 |                         format!("task.{}", task_id_clone),
622 |                         crate::bus::BusMessage::TaskUpdate {
623 |                             task_id: task_id_clone.clone(),
624 |                             state: crate::a2a::types::TaskState::Working,
625 |                             message: Some(serde_json::to_string(&event_data).unwrap_or_default()),
626 |                         },
627 |                     );
628 |                 }
629 |             }
630 |         });
631 | 
632 |         // Use prompt_with_events for streaming
633 |         let registry = match crate::provider::ProviderRegistry::from_vault().await {
634 |             Ok(r) => Arc::new(r),
635 |             Err(e) => {
636 |                 tracing::error!("Failed to load provider registry: {}", e);
637 |                 if let Some(mut t) = tasks.get_mut(&task_id) {
638 |                     t.status.state = TaskState::Failed;
639 |                     t.status.timestamp = Some(chrono::Utc::now().to_rfc3339());
640 |                 }
641 |                 return;
642 |             }
643 |         };
644 | 
645 |         match session
646 |             .prompt_with_events(&prompt, event_tx, registry)
647 |             .await
648 |         {
649 |             Ok(result) => {
650 |                 let result_text = result.text;
