     server: &A2AServer,
     request: JsonRpcRequest,
 ) -> Result<serde_json::Value, JsonRpcError> {
     let params: TaskQueryParams = serde_json::from_value(request.params)
         .map_err(|e| JsonRpcError::invalid_params(format!("Invalid parameters: {}", e)))?;

